# Merge all chunks
merged = {'nodes': [], 'edges': [], 'hyperedges': []}
seen_nodes = set()
for chunk in chunks:
    for node in chunk.get('nodes', []):
        if node['id'] not in seen_nodes:
            seen_nodes.add(node['id'])
            merged['nodes'].append(node)
    merged['edges'].extend(chunk.get('edges', []))
    merged['hyperedges'].extend(chunk.get('hyperedges', []))

Path('graphify-out/.graphify_semantic_new.json').write_text(json.dumps(merged, indent=2))
print(f'Merged semantic new: {len(merged["nodes"])} nodes, {len(merged["edges"])} edges')
